head.script:
/* 하위작업장 팝업(lo_100_07_06p.xml)
    물류>공통(통합)>작업장관리 에서 하위작업장버튼으로 호출
 */
scwin.onpageload = function () {
    var params = $c.data.getParameter();
};

scwin.MSG_LO_ERR_001 = "변경할 상위작업장을 선택하십시오.";
scwin.pos_rowSts = 0;

scwin.f_newCtrt = function () {

};

scwin.onUdcCompleted = function() {

    scwin.f_defaultValue();
    scwin.f_Retrieve();
};

scwin.f_defaultValue = function () {

    $c.gus.cfDisableKey();
    $c.gus.cfDisableBtn([btn_save]);

    var oCtrtObject = $c.data.getParameter();

    /*
    var oCtrtObject = {
        //wrkPlCd : "4E11"
        //,wrkPlNm : "인천34창고"
        wrkPlCd : "4P01"
        ,wrkPlNm : "인천1부두11선석"
    };
    */
//console.log("scwin.onUdcCompleted~~~");
//console.log(oCtrtObject);

    //ed_upperWrkPlCd.setValue(oCtrtObject.wrkPlCd);
    ed_upperWrkPlCd.setValue(scwin.f_upperWrkPlCdFormat(oCtrtObject.wrkPlCd));
    ed_upperWrkPlNm.setValue(oCtrtObject.wrkPlNm);
};

scwin.f_addrow = async  function () {
    if (ed_upperWrkPlCd.getValue() == "") {
        await $c.gus.cfAlertMsg(scwin.MSG_LO_ERR_001);
        return false;
    }

    var row = ds_wrkpl.insertRow();
    ds_wrkpl.setCellData(row, "upperWrkPlCd", ed_upperWrkPlCd.getValue());
    gr_wrkpl.setFocusedCell(row, "upperWrkPlCd", false);

    $c.gus.cfEnableBtnOnly([btn_save]);

  //  console('add eddd');
};

scwin.f_delRow = function() {
	ds_wrkpl.setCellData(ds_wrkpl.getRowPosition(), "upperWrkPlCd","");
	$c.gus.cfEnableBtnOnly([btn_save]);
};

scwin.f_Retrieve = async function () {

    //조회 필수 조건 check
    if (ed_upperWrkPlCd.getValue().trim() == "") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002,["작업장"]);
        return false;
    }

    $p.executeSubmission(sbm_retrieve);
};

scwin.f_Save = async function () {
    scwin.pos_rowSts = ds_wrkpl.getRowPosition();

    //행의 상태 코드 (초기상태:"R", 갱신:"U", 삽입:"C", 삭제:"D", 삽입 후 삭제:"V")
    if (ds_wrkpl.getModifiedIndex().length < 1) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["하위작업장"]);
        return false;
    }

    if (await scwin.f_ReqFieldChk()) {
        $p.executeSubmission(sbm_save);
    }
};

scwin.f_ReqFieldChk = async function () {
    //필수입력항목 체크
    if (await $c.gus.cfValidate([gr_wrkpl], null, true)) {
        return true;
    } else {
        return false;
    }
};

scwin.sbm_retrieve_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
    var rowcnt = ds_wrkpl.getRowCount();
	//if (rowcnt == 0) {
    //    await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
	//}

    tbx_totalRows.setValue(rowcnt);
};

scwin.sbm_retrieve_submiterror = function (e) {

};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

scwin.btn_close_onclick = function (e) {
    $c.win.closePopup();
};

scwin.gr_wrkpl_onrowindexchange = function (rowIndex, oldRow) {

};

scwin.gr_wrkpl_oncellclick = function (rowIndex, columnIndex, columnId) {
    //그리드 컬럼 속성은 textimage 로 사용함.
    if(ds_wrkpl.getRowStatus(rowIndex) != "R"){
        gr_wrkpl.setReadOnly("cell", rowIndex, "wrkPlCd", false);
        gr_wrkpl.setReadOnly("cell", rowIndex, "wrkPlNm", false);
    }else{
        gr_wrkpl.setReadOnly("cell", rowIndex, "wrkPlCd", true);
        gr_wrkpl.setReadOnly("cell", rowIndex, "wrkPlNm", true);
    }
};

scwin.gridView_imageClickFunc = function(rowIndex, colId, nowValue){
    if(gr_wrkpl.getFocusedRowStatus() == "C"){
        console.log('image clicked!');
    }
}


scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    scwin.f_Retrieve();
};

scwin.sbm_save_submiterror = function (e) {
    console.log("error~~~");
};

scwin.f_cancel = function(){
    console.log("f_cancel~~~");
}

scwin.gr_wrkpl_ontextimageclick = function (rowIndex, columnIndex) {
    scwin.f_openPopup();
};

scwin.udc_comCodeGridCallback = function(rtnList){
    if ( rtnList != null && rtnList[0] != "N/A") {
    	//return value Assign
    	ds_wrkpl.setCellData(ds_wrkpl.getRowPosition(),"wrkPlCd", rtnList[0]);//거래처번호
    	ds_wrkpl.setCellData(ds_wrkpl.getRowPosition(),"wrkPlNm", rtnList[1]);	//거래처명					
    }else{
        ds_wrkpl.setCellData(ds_wrkpl.getRowPosition(),"wrkPlCd", "");//거래처번호
    	ds_wrkpl.setCellData(ds_wrkpl.getRowPosition(),"wrkPlNm", "");	//거래처명		
    }
};

scwin.gr_wrkpl_onafteredit = function (rowIndex, columnIndex, value, info) { //info 를 추가
//console.log("scwin.gr_wrkpl_onafteredit ~~~~~~~~~~~");
    var colId = gr_wrkpl.getColumnID(columnIndex)

    if (info.type === 'mousedown') { //테스트해보면 입력에는 keydown, 이미지클릭시 mousedown
        return false; // onafteredit 로직 중단
    }

    if(colId == 'wrkPlCd'){
        /*
        if(ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(),"wrkPlCd") != '' ){
            if (ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(),"wrkPlNm") != '')
            {
                ds_wrkpl.setCellData(ds_wrkpl.getRowPosition(),"wrkPlNm",'');
            }
        }
        */

        //if(ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(),"wrkPlCd") == ''){
            ds_wrkpl.setCellData(ds_wrkpl.getRowPosition(),"wrkPlNm",'');
        //}

        scwin.f_openPopup();
    }

    if(colId == 'wrkPlNm'){
        /*
        if(ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(),"wrkPlNm") != '' ){
            if (ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(),"wrkPlCd") != '')
            {
                ds_wrkpl.setCellData(ds_wrkpl.getRowPosition(),"wrkPlCd",'')
            }

        }
        */

        //if(ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(),"wrkPlNm") == ''){
            ds_wrkpl.setCellData(ds_wrkpl.getRowPosition(),"wrkPlCd",'');
        //}

        scwin.f_openPopup();
    }
};

scwin.f_openPopup = function(){
console.log("scwin.f_openPopup ~~~~~~~~~~~");
    //var rtnList = new Array();
    udc_comCodeGrid.setSelectId('retrieveWrkPlInfo');
	rtnList = udc_comCodeGrid.cfCommonPopUp(scwin.udc_comCodeGridCallback,	
							ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(),"wrkPlCd"),	
							ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(),"wrkPlNm"),	
							"T",		
							'5',		
							null,	
							'150,170',
							null,		
							null,   
							'440',	
							'500',	
							null,		
							null,		
							null,		
							null,		
							null,		
							null);

     ds_wrkpl.setCellData(ds_wrkpl.getRowPosition(),"wrkPlCd",'');
     ds_wrkpl.setCellData(ds_wrkpl.getRowPosition(),"wrkPlNm",'');
};


scwin.f_upperWrkPlCdFormat = function (value){
    //var str = "6BC3";

    const regex = /\d{1}/gi;
    var str = "";
    if(!$c.gus.cfIsNull(value)){
        for(var i=0;i< value.length;i++){
            if(i == 0 && regex.test(value[i])){
                str+=value[i];
            }

            if(i == 1 && !regex.test(value[i])){
                str+=value[i];
            }

            if(i > 1 && regex.test(value[i])){
                str+=value[i];
            }
        }
    }

    return str;
};
